package com.scau.dormrepair.service.impl;
import com.scau.dormrepair.common.*;import com.scau.dormrepair.domain.command.*;import com.scau.dormrepair.domain.entity.*;import com.scau.dormrepair.domain.enums.*;import com.scau.dormrepair.domain.view.*;import com.scau.dormrepair.exception.*;import com.scau.dormrepair.mapper.*;import com.scau.dormrepair.service.WorkOrderService;import java.time.LocalDateTime;import java.util.*;
public class WorkOrderServiceImpl implements WorkOrderService {
private static final int MAX_COMPLETION_IMAGE_COUNT=3;private static final int MAX_NOTE_LENGTH=1000;private final MyBatisExecutor myBatisExecutor;public WorkOrderServiceImpl(MyBatisExecutor myBatisExecutor){this.myBatisExecutor=myBatisExecutor;}
@Override public Long assign(AssignWorkOrderCommand command){if(command.repairRequestId()==null)throw new BusinessException("报修单 ID 不能为空");if(command.adminId()==null||command.workerId()==null)throw new BusinessException("派单管理员和维修人员不能为空");if(command.priority()==null)throw new BusinessException("工单优先级不能为空");return myBatisExecutor.executeWrite(session->{RepairRequestMapper repairRequestMapper=session.getMapper(RepairRequestMapper.class);WorkOrderMapper workOrderMapper=session.getMapper(WorkOrderMapper.class);WorkOrderRecordMapper workOrderRecordMapper=session.getMapper(WorkOrderRecordMapper.class);AuditLogMapper auditLogMapper=session.getMapper(AuditLogMapper.class);RepairRequest repairRequest=repairRequestMapper.selectById(command.repairRequestId());if(repairRequest==null)throw new ResourceNotFoundException("未找到报修单，ID="+command.repairRequestId());if(workOrderMapper.selectByRepairRequestId(command.repairRequestId())!=null)throw new BusinessException("该报修单已经生成工单");if(repairRequest.getStatus()==RepairRequestStatus.COMPLETED||repairRequest.getStatus()==RepairRequestStatus.CANCELLED||repairRequest.getStatus()==RepairRequestStatus.REJECTED)throw new BusinessException("当前报修状态不允许再次派单");WorkOrder workOrder=new WorkOrder();workOrder.setWorkOrderNo(BusinessNumberGenerator.nextWorkOrderNo());workOrder.setRepairRequestId(command.repairRequestId());workOrder.setAdminId(command.adminId());workOrder.setWorkerId(command.workerId());workOrder.setPriority(command.priority());workOrder.setStatus(WorkOrderStatus.ASSIGNED);workOrder.setAssignmentNote(normalizeOptional(command.assignmentNote()));workOrder.setAssignedAt(LocalDateTime.now());workOrderMapper.insert(workOrder);repairRequestMapper.updateAssignmentInfo(command.repairRequestId(),RepairRequestStatus.ASSIGNED,command.adminId(),command.workerId());WorkOrderRecord workOrderRecord=new WorkOrderRecord();workOrderRecord.setWorkOrderId(workOrder.getId());workOrderRecord.setOperatorId(command.adminId());workOrderRecord.setStatus(WorkOrderStatus.ASSIGNED);workOrderRecord.setRecordNote(normalizeOptional(command.assignmentNote()));workOrderRecordMapper.insert(workOrderRecord);AuditLogSupport.append(auditLogMapper,command.adminId(),"WORK_ORDER_ASSIGN","WORK_ORDER",String.valueOf(workOrder.getId()),workOrder.getWorkOrderNo(),null,"request="+repairRequest.getRequestNo()+", workerId="+command.workerId()+", priority="+command.priority());return workOrder.getId();});}
@Override public void updateStatus(UpdateWorkOrderStatusCommand command){if(command.workOrderId()==null||command.operatorId()==null||command.status()==null)throw new BusinessException("工单状态更新参数不完整");myBatisExecutor.executeWrite(session->{WorkOrderMapper workOrderMapper=session.getMapper(WorkOrderMapper.class);RepairRequestMapper repairRequestMapper=session.getMapper(RepairRequestMapper.class);WorkOrderRecordMapper workOrderRecordMapper=session.getMapper(WorkOrderRecordMapper.class);WorkOrderCompletionImageMapper completionImageMapper=session.getMapper(WorkOrderCompletionImageMapper.class);AuditLogMapper auditLogMapper=session.getMapper(AuditLogMapper.class);WorkOrder workOrder=workOrderMapper.selectById(command.workOrderId());if(workOrder==null)throw new ResourceNotFoundException("未找到工单，ID="+command.workOrderId());RepairRequest repairRequest=repairRequestMapper.selectById(workOrder.getRepairRequestId());if(repairRequest==null)throw new ResourceNotFoundException("未找到对应报修单，ID="+workOrder.getRepairRequestId());validateStatusUpdate(workOrder,command);LocalDateTime acceptedAt=workOrder.getAcceptedAt();LocalDateTime completedAt=workOrder.getCompletedAt();if(command.status()==WorkOrderStatus.ACCEPTED&&acceptedAt==null)acceptedAt=LocalDateTime.now();if(command.status()==WorkOrderStatus.WAITING_CONFIRMATION)completedAt=LocalDateTime.now();if(command.status()==WorkOrderStatus.IN_PROGRESS||command.status()==WorkOrderStatus.WAITING_PARTS)completedAt=null;String completionNote=workOrder.getCompletionNote();List<String> completionImageUrls=List.of();if(command.status()==WorkOrderStatus.WAITING_CONFIRMATION){completionNote=normalizeCompletionNote(command.completionNote());completionImageUrls=sanitizeImageUrls(command.completionImageUrls());}workOrderMapper.updateStatus(workOrder.getId(),command.status(),acceptedAt,completedAt,completionNote);if(command.status()==WorkOrderStatus.WAITING_CONFIRMATION){completionImageMapper.deleteByWorkOrderId(workOrder.getId());if(!completionImageUrls.isEmpty())completionImageMapper.batchInsert(workOrder.getId(),completionImageUrls);}RepairRequestStatus nextRequestStatus=resolveRequestStatus(repairRequest.getStatus(),command.status());repairRequestMapper.updateStatus(workOrder.getRepairRequestId(),nextRequestStatus,nextRequestStatus==RepairRequestStatus.COMPLETED?completedAt:null);WorkOrderRecord workOrderRecord=new WorkOrderRecord();workOrderRecord.setWorkOrderId(workOrder.getId());workOrderRecord.setOperatorId(command.operatorId());workOrderRecord.setStatus(command.status());workOrderRecord.setRecordNote(resolveRecordNote(command));workOrderRecordMapper.insert(workOrderRecord);AuditLogSupport.append(auditLogMapper,command.operatorId(),"WORK_ORDER_STATUS_UPDATE","WORK_ORDER",String.valueOf(workOrder.getId()),workOrder.getWorkOrderNo(),workOrder.getStatus()==null?null:workOrder.getStatus().name(),command.status().name());return null;});}
@Override public List<ActiveWorkOrderView> listActiveWorkOrders(int limit){int safeLimit=Math.min(Math.max(limit,1),20);return myBatisExecutor.executeRead(session->decorateActiveRows(session.getMapper(WorkOrderMapper.class).selectActiveWorkOrders(safeLimit)));}
@Override public List<ActiveWorkOrderView> listWorkerActiveWorkOrders(Long workerId,int limit){if(workerId==null)throw new BusinessException("维修员 ID 不能为空");int safeLimit=Math.min(Math.max(limit,1),20);return myBatisExecutor.executeRead(session->decorateActiveRows(session.getMapper(WorkOrderMapper.class).selectWorkerActiveWorkOrders(workerId,safeLimit)));}
@Override public List<WorkOrderDetailView> listAdminTrackedWorkOrders(int limit){int safeLimit=Math.min(Math.max(limit,1),20);return myBatisExecutor.executeRead(session->decorateTrackedRows(session.getMapper(WorkOrderMapper.class).selectTrackedWorkOrders(safeLimit)));}
@Override public List<WorkOrderDetailView> listWorkerTrackedWorkOrders(Long workerId,int limit){if(workerId==null)throw new BusinessException("维修员 ID 不能为空");int safeLimit=Math.min(Math.max(limit,1),20);return myBatisExecutor.executeRead(session->decorateTrackedRows(session.getMapper(WorkOrderMapper.class).selectWorkerTrackedWorkOrders(workerId,safeLimit)));}
@Override public WorkOrderDetailView getAdminWorkOrderDetail(Long workOrderId){if(workOrderId==null)throw new BusinessException("工单 ID 不能为空");return myBatisExecutor.executeRead(session->loadDetail(session,session.getMapper(WorkOrderMapper.class).selectTrackedWorkOrderDetail(workOrderId),workOrderId));}
@Override public WorkOrderDetailView getWorkerWorkOrderDetail(Long workerId,Long workOrderId){if(workerId==null||workOrderId==null)throw new BusinessException("工单查看参数不完整");return myBatisExecutor.executeRead(session->{WorkOrderMapper workOrderMapper=session.getMapper(WorkOrderMapper.class);WorkOrder workOrder=workOrderMapper.selectById(workOrderId);if(workOrder==null)throw new ResourceNotFoundException("未找到对应的工单，ID="+workOrderId);if(workOrder.getWorkerId()==null||!workerId.equals(workOrder.getWorkerId()))throw new BusinessException("当前账号无权查看这张工单。");return loadDetail(session,workOrderMapper.selectWorkerTrackedWorkOrderDetail(workerId,workOrderId),workOrderId);});}
private WorkOrderDetailView loadDetail(org.apache.ibatis.session.SqlSession session,WorkOrderDetailView detailView,Long workOrderId){if(detailView==null)throw new ResourceNotFoundException("未找到对应的工单，ID="+workOrderId);WorkOrderRecordMapper workOrderRecordMapper=session.getMapper(WorkOrderRecordMapper.class);WorkOrderCompletionImageMapper completionImageMapper=session.getMapper(WorkOrderCompletionImageMapper.class);detailView.setRecords(workOrderRecordMapper.selectTimelineByWorkOrderId(workOrderId));detailView.setCompletionImageUrls(completionImageMapper.selectByWorkOrderId(workOrderId).stream().map(WorkOrderCompletionImage::getImageUrl).filter(item->item!=null&&!item.isBlank()).toList());applyTimeout(detailView);return detailView;}
private void validateStatusUpdate(WorkOrder workOrder,UpdateWorkOrderStatusCommand command){if(workOrder.getWorkerId()==null||!workOrder.getWorkerId().equals(command.operatorId()))throw new BusinessException("当前账号无权更新这张工单。");WorkOrderStatus currentStatus=workOrder.getStatus();if(currentStatus==null)throw new BusinessException("当前工单状态异常，无法继续处理。");if(isFinishedStatus(currentStatus))throw new BusinessException("当前工单已结束，不能再回退或重复更新。");if(currentStatus==command.status())throw new BusinessException("请选择新的处理状态后再提交。");if(!allowedNextStatuses(currentStatus).contains(command.status()))throw new BusinessException("当前工单状态不允许直接流转到目标状态。");}
private EnumSet<WorkOrderStatus> allowedNextStatuses(WorkOrderStatus currentStatus){return switch(currentStatus){case ASSIGNED->EnumSet.of(WorkOrderStatus.ACCEPTED,WorkOrderStatus.REJECTED,WorkOrderStatus.CANCELLED);case ACCEPTED->EnumSet.of(WorkOrderStatus.IN_PROGRESS,WorkOrderStatus.WAITING_PARTS,WorkOrderStatus.CANCELLED);case IN_PROGRESS->EnumSet.of(WorkOrderStatus.WAITING_PARTS,WorkOrderStatus.WAITING_CONFIRMATION,WorkOrderStatus.CANCELLED);case WAITING_PARTS->EnumSet.of(WorkOrderStatus.IN_PROGRESS,WorkOrderStatus.WAITING_CONFIRMATION,WorkOrderStatus.CANCELLED);case WAITING_CONFIRMATION,COMPLETED,REJECTED,CANCELLED->EnumSet.noneOf(WorkOrderStatus.class);};}
private boolean isFinishedStatus(WorkOrderStatus workOrderStatus){return workOrderStatus==WorkOrderStatus.COMPLETED||workOrderStatus==WorkOrderStatus.CANCELLED||workOrderStatus==WorkOrderStatus.REJECTED;}
private RepairRequestStatus resolveRequestStatus(RepairRequestStatus currentRequestStatus,WorkOrderStatus workOrderStatus){return switch(workOrderStatus){case ASSIGNED->RepairRequestStatus.ASSIGNED;case ACCEPTED,IN_PROGRESS,WAITING_PARTS->currentRequestStatus==RepairRequestStatus.REWORK_IN_PROGRESS?RepairRequestStatus.REWORK_IN_PROGRESS:RepairRequestStatus.IN_PROGRESS;case WAITING_CONFIRMATION->RepairRequestStatus.PENDING_CONFIRMATION;case COMPLETED->RepairRequestStatus.COMPLETED;case REJECTED->RepairRequestStatus.REJECTED;case CANCELLED->RepairRequestStatus.CANCELLED;};}
private List<ActiveWorkOrderView> decorateActiveRows(List<ActiveWorkOrderView> rows){rows.forEach(this::applyTimeout);return rows;}private List<WorkOrderDetailView> decorateTrackedRows(List<WorkOrderDetailView> rows){rows.forEach(this::applyTimeout);return rows;}private void applyTimeout(ActiveWorkOrderView row){if(row==null)return;TimeoutLevel level=RepairSlaPolicy.resolveWorkOrderLevel(row.getStatus(),row.getAssignedAt(),row.getAcceptedAt());row.setTimeoutLevel(level);row.setTimeoutLabel(RepairSlaPolicy.resolveWorkOrderLabel(row.getStatus(),level));}private void applyTimeout(WorkOrderDetailView row){if(row==null)return;TimeoutLevel level=RepairSlaPolicy.resolveWorkOrderLevel(row.getStatus(),row.getAssignedAt(),row.getAcceptedAt());row.setTimeoutLevel(level);row.setTimeoutLabel(RepairSlaPolicy.resolveWorkOrderLabel(row.getStatus(),level));}
private String normalizeCompletionNote(String value){String normalized=normalizeOptional(value);if(normalized==null)throw new BusinessException("完工时请填写简短处理说明。");if(normalized.length()>MAX_NOTE_LENGTH)throw new BusinessException("处理说明不能超过 "+MAX_NOTE_LENGTH+" 个字符。");return normalized;}private List<String> sanitizeImageUrls(List<String> imageUrls){if(imageUrls==null)return List.of();List<String> normalized=imageUrls.stream().filter(item->item!=null&&!item.isBlank()).map(String::trim).distinct().toList();if(normalized.size()>MAX_COMPLETION_IMAGE_COUNT)throw new BusinessException("完工凭证最多上传 "+MAX_COMPLETION_IMAGE_COUNT+" 张图片。");return normalized;}private String resolveRecordNote(UpdateWorkOrderStatusCommand command){String note=normalizeOptional(command.recordNote());if(note!=null)return note;return command.status()==WorkOrderStatus.WAITING_CONFIRMATION?normalizeOptional(command.completionNote()):null;}private String normalizeOptional(String value){if(value==null)return null;String trimmed=value.trim();if(trimmed.isEmpty())return null;if(trimmed.length()>MAX_NOTE_LENGTH)throw new BusinessException("备注内容不能超过 "+MAX_NOTE_LENGTH+" 个字符。");return trimmed;}
}